        var TextDirection = Java.use("androidx.core.text.TextDirectionHeuristicsCompat");
        TextDirection.isRtlText.implementation = function (i) {
            var result = this.isRtlText(i);
            console.log("Direction check for char: " + i + " Result: " + result);
            return result;
        };
    });
    ```
